mapper.select:
SELECT
    (SELECT COUNT(*) FROM batch_customer WHERE del_flag = 0 AND customer_type = 1
         AND phone = #{branchPhone} 
    ) AS branch_total,
    (SELECT COUNT(*) FROM batch_customer WHERE del_flag = 0 AND customer_type = 2
         AND branch_phone = #{branchPhone} 
    ) AS provider_total,
    (SELECT COUNT(*) FROM batch_customer WHERE del_flag = 0 AND customer_type = 3
         AND branch_phone = #{branchPhone} 
    ) AS individual_total,
    (SELECT COUNT(*) FROM batch_customer WHERE del_flag = 0
         AND (branch_phone = #{branchPhone} OR phone = #{branchPhone}) 
    ) AS account_total,
    (SELECT COUNT(*) FROM batch_customer WHERE del_flag = 0 AND DATE(create_time) = CURDATE()
         AND (branch_phone = #{branchPhone} OR phone = #{branchPhone}) 
    ) AS account_today_new,
    (SELECT COALESCE(SUM(cpl.consume_value), 0) FROM batch_computing_power_log cpl

        INNER JOIN batch_customer c ON cpl.phone = c.phone AND c.del_flag = 0 AND (c.branch_phone = #{branchPhone} OR c.phone = #{branchPhone})

        WHERE DATE(cpl.create_time) = CURDATE()
    ) AS computing_today_consume,
    (SELECT COALESCE(SUM(vgl.generate_count), 0) FROM batch_video_generate_log vgl

        INNER JOIN batch_customer c ON vgl.phone = c.phone AND c.del_flag = 0 AND (c.branch_phone = #{branchPhone} OR c.phone = #{branchPhone})

        WHERE DATE(vgl.create_time) = CURDATE() AND vgl.status = 0
    ) AS video_today_generate,
    (SELECT COALESCE(SUM(qcs.scan_count), 0) FROM batch_qr_code_stat qcs

        INNER JOIN batch_customer c ON qcs.phone = c.phone AND c.del_flag = 0 AND (c.branch_phone = #{branchPhone} OR c.phone = #{branchPhone})

        WHERE qcs.stat_date = CURDATE()
    ) AS qr_scan_today,
    (SELECT COALESCE(SUM(qcs.download_count), 0) FROM batch_qr_code_stat qcs

        INNER JOIN batch_customer c ON qcs.phone = c.phone AND c.del_flag = 0 AND (c.branch_phone = #{branchPhone} OR c.phone = #{branchPhone})

        WHERE qcs.stat_date = CURDATE()
    ) AS qr_download_today,
    (SELECT COALESCE(SUM(qcs.register_count), 0) FROM batch_qr_code_stat qcs

        INNER JOIN batch_customer c ON qcs.phone = c.phone AND c.del_flag = 0 AND (c.branch_phone = #{branchPhone} OR c.phone = #{branchPhone})

        WHERE qcs.stat_date = CURDATE()
    ) AS qr_register_today,
    (SELECT COALESCE(SUM(sales_amount), 0) FROM batch_home_news WHERE del_flag = 0 AND status = 0 AND DATE(update_time) = CURDATE()) AS news_sales_amount,
    (SELECT COUNT(*) FROM batch_customer WHERE del_flag = 0 AND customer_type = 2 AND branch_phone = #{branchPhone}) AS branch_service_provider_count,
    (SELECT COUNT(*) FROM batch_customer WHERE del_flag = 0 AND customer_type = 3 AND branch_phone = #{branchPhone}) AS branch_individual_count,
    (
        (SELECT COALESCE(SUM(max_individual), 0) FROM batch_customer WHERE del_flag = 0 AND customer_type = 2 AND branch_phone = #{branchPhone})
        - (SELECT COUNT(*) FROM batch_customer WHERE del_flag = 0 AND customer_type = 3 AND branch_phone = #{branchPhone})
    ) AS branch_service_provider_remain,
    (
        (SELECT COALESCE(MAX(max_service_provider), 0) FROM batch_customer WHERE del_flag = 0 AND customer_type = 1 AND phone = #{branchPhone})
        - (SELECT COUNT(*) FROM batch_customer WHERE del_flag = 0 AND customer_type = 2 AND branch_phone = #{branchPhone})
    ) AS branch_max_service_provider_remain

SELECT c.customer_id, c.customer_type, c.customer_name, c.contact_name, c.phone, c.parent_phone, c.branch_phone, c.status, c.create_time
FROM batch_customer c
WHERE c.del_flag = 0
 AND c.customer_type = #{customerType} 

 AND DATE(c.create_time) >= #{startDate} 
 AND DATE(c.create_time) <= #{endDate} 
ORDER BY c.create_time DESC

SELECT n.news_id, n.news_title, n.champion_name, n.sales_amount, n.status, n.update_time
FROM batch_home_news n
WHERE n.del_flag = 0
 AND DATE(n.update_time) >= #{startDate} 
 AND DATE(n.update_time) <= #{endDate} 
ORDER BY n.update_time DESC
